mapper.select:
SELECT , p.patient_name, p.patient_no, p.gender, p.age, du.real_name AS doctor_name, li.item_name, li.item_code, li.item_price, lu.real_name AS lab_doctor_name FROM lab_apply l LEFT JOIN patient p ON l.patient_id = p.patient_id LEFT JOIN sys_user du ON l.doctor_id = du.user_id LEFT JOIN lab_item li ON l.item_id = li.item_id LEFT JOIN sys_user lu ON l.lab_doctor_id = lu.user_id
AND l.status = #{status} AND l.patient_id = #{patientId} AND l.doctor_id = #{doctorId} AND l.lab_doctor_id = #{labDoctorId}
ORDER BY l.create_time DESC

mapper.update:
UPDATE lab_apply
status = #{status}, lab_doctor_id = #{labDoctorId}, lab_result = #{labResult}, lab_value = #{labValue}, lab_time = #{labTime}, clinical_info = #{clinicalInfo},
WHERE apply_id = #{applyId}
